216	  };
217	
218	  return nodeHealthCheck.status?.reason && withPopover ? (
219	    <Popover
220	      maxWidth="30rem"
221	      position={showPausePopover ? "right" : "top"}
222	      isVisible={popoverVisible}
223	      shouldOpen={() => setPopoverVisible(true)}
224	      shouldClose={onShouldClose}
225	      bodyContent={
226	        <PopoverContent
227	          pauseReasons={pauseReasons}
228	          showPausePopover={showPausePopover}
229	          nodeHealthCheck={nodeHealthCheck}
230	          phase={phase}
231	          reason={nodeHealthCheck.status?.reason}
232	          onEditPauseReasons={() => setPopoverVisible(false)}
233	        />
234	      }
235	    >
236	      {content}
237	    </Popover>
238	  ) : (
239	    content
240	  );
241	};
242	
243	export default NodeHealthCheckStatus;

